INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('optometrist-moex-00474', 'optometrist', 'optometrist-moex-113-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關角膜地圖儀各項參數的敘述，下列何者錯誤？', '["比較相隔180度的軸線等距離對應點屈光度的差值，稱作角膜表面非對稱指數（SurfaceAsymmetryIndex, SAI），角膜的對稱性愈高，非對稱指數SAI的數值就愈低", "最常使用來偵測角膜不規則率及圓錐角膜的指數是下上角膜屈光值差異（Inferior-Superior value, I-S value）", "角膜表面規則指數（SurfaceRegularityIndex,SRI）是指角膜表面平滑度，主要是測量角膜中心與中心旁 （Paracentral）的角膜規則度，表面愈不規則，SRI值愈大", "偏心率（Eccentricity,E值），正常值約在0.40～0.57之間。E值愈低，表示角膜周邊愈平坦"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "b745f9722863", "answer_pdf_sha1": "cd693ea90406", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00475', 'optometrist', 'optometrist-moex-113-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關配戴隱形眼鏡產生的併發症，下列敘述何者錯誤？', '["戴用角膜塑型片，最常見的角膜微生物感染是金黃色葡萄球菌", "隱形眼鏡戴著睡覺，常會造成角膜缺氧、角膜水腫", "急性紅眼症（Contactlensacuteredeye,CLARE），常發生在一早醒來，與格蘭氏陰性菌有關", "配戴水膠軟式隱形眼鏡產生角膜水腫，可以改配透氧率較高或基弧較平的鏡片來改善"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "b745f9722863", "answer_pdf_sha1": "cd693ea90406", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00476', 'optometrist', 'optometrist-moex-113-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關隱形眼鏡導致角膜上方弓形表皮破損（superiorepithelialarcuatelesions,SEALs），下列敘述何者錯誤？', '["Hydrogel材質的隱形眼鏡比siliconehydrogel的材質更容易發生", "通常是病患摘下鏡片，傷口暴露後會感覺到疼痛", "一旦發生此疾病，建議停戴隱形眼鏡1～2天", "如果重複發作，建議重配隱形眼鏡或更換不同材質的隱形眼鏡"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "b745f9722863", "answer_pdf_sha1": "cd693ea90406", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00477', 'optometrist', 'optometrist-moex-113-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '關於隱形眼鏡的沉澱物（deposits），下列敘述何者錯誤？', '["軟式隱形眼鏡所產生的併發症多與角膜水腫及沉澱物相關", "日拋、單週拋、雙週拋等隱形眼鏡的盛行，減少了隱形眼鏡的沉澱物的發生率", "因為軟式隱形眼鏡的鏡面是親水性的，因此比較傾向會有沉澱物", "水膠的鏡片比起矽水膠鏡片更容易有隱形眼鏡的脂質沉澱物"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "b745f9722863", "answer_pdf_sha1": "cd693ea90406", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00478', 'optometrist', 'optometrist-moex-113-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '關於軟式隱形眼鏡的沉澱物（deposits），下列何者錯誤？', '["主要可以分成有機（organic）及無機（inorganic）兩種", "蛋白質（protein）是相當常見的有機沉澱物", "鏽斑（rustspot）的沉澱物常常和使用井水清潔隱形眼鏡有關", "膠凍塊（Jellybumps）是最常見的有機類沉澱物"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "b745f9722863", "answer_pdf_sha1": "cd693ea90406", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00479', 'optometrist', 'optometrist-moex-113-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '關於抗生素使用在隱形眼鏡相關的併發症，下列敘述何者錯誤？', '["通常需要使用到抗生素的情況為感染性角膜炎、細菌性結膜炎、眼瞼炎和角膜刮傷等", "Fluoroquinolone類抗生素抗菌的機轉主要有兩個，所以比較不易具有抗藥性。雖目前使用繁多，尚未看 到其抗藥性的增加", "如需使用抗生素合併類固醇的藥水時，次數最好不要低於四次，不然不易達到有效抗生素治療濃度而篩 選出有抗藥性的菌株", "使用隱形眼鏡時，若發生角膜感染，最常見的是綠膿桿菌，因此選擇抗生素時，要將此點考慮進去"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "b745f9722863", "answer_pdf_sha1": "cd693ea90406", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00480', 'optometrist', 'optometrist-moex-113-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '驗配硬式交替型雙焦隱形眼鏡，其截斷面應放在下眼瞼下，則鏡片的垂直直徑應至少比水平可見虹膜直徑 小多少？', '["1mm", "2mm", "3mm", "4mm"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "b745f9722863", "answer_pdf_sha1": "cd693ea90406", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00481', 'optometrist', 'optometrist-moex-113-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '關於圓錐角膜特殊隱形眼鏡驗配之敘述，下列何者錯誤？', '["在初期形成圓錐角膜時期，可利用軟式隱形眼鏡做有效的視覺矯正", "利用硬式角膜鏡片來做圓錐角膜視覺矯正時，會比利用球面水膠軟式隱形眼鏡矯正時更增加高階像差", "利用三點接觸（Three-point Touch）驗配原理時，使用螢光染色觀察角膜頂點區域，螢光素輪廓相對變 暗，是因為淚鏡厚度低於20 μm", "小鞏膜鏡片（MiniscleralLenses），其直徑範圍為15.1~18.0mm，當一旦定位到眼睛上時，鏡片的中心間 隙應約為200 μm"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "b745f9722863", "answer_pdf_sha1": "cd693ea90406", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00482', 'optometrist', 'optometrist-moex-113-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '下列何者不是軟式治療性隱形眼鏡的疾病適應症？', '["復發性角膜糜爛", "水泡性角膜病變", "雷射屈光角膜切除術（photorefractivekeratectomy）後", "嚴重細菌性角膜炎"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "b745f9722863", "answer_pdf_sha1": "cd693ea90406", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00483', 'optometrist', 'optometrist-moex-113-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '關於垂重稜鏡設計之軟式隱形眼鏡，下列敘述何者錯誤？', '["在增加稜鏡厚度的區域會降低傳氧率", "此設計對眼睛較敏感的人會感到不舒服", "採垂重稜鏡設計之軟式散光隱形眼鏡，在眼睛通常會出現鏡片過度向下", "雙眼都配戴此設計鏡片，會引起垂直稜鏡效應導致不舒服"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "b745f9722863", "answer_pdf_sha1": "cd693ea90406", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
